import collections
import json


def size_bytes(size):
    parts = str(size).split()
    if not parts:
        return 0
    try:
        number = float(parts[0])
    except ValueError:
        return 0
    unit = parts[1].lower() if len(parts) > 1 else "bytes"
    return number * {"bytes": 1, "kb": 1024, "mb": 1024**2, "gb": 1024**3}.get(unit, 1)


data = json.load(open("designflow_sandbox_schema_report.json", encoding="utf-8"))
relations = data["relations"]
columns = data["columns"]
constraints = data["constraints"]
foreign_keys = data["foreign_keys"]
indexes = data["indexes"]

print("Relations by schema/kind")
for key, count in sorted(collections.Counter((r["schema"], r["kind"]) for r in relations).items()):
    print(key, count)

print("\nColumns by schema")
for schema, count in sorted(collections.Counter(c["schema"] for c in columns).items()):
    print(schema, count)

print("\nTop table sizes")
for rel in sorted([r for r in relations if r["kind"] == "table"], key=lambda r: size_bytes(r["total_size"]), reverse=True)[:25]:
    print(f"{rel['schema']}.{rel['name']} {rel['total_size']}")

print("\nForeign-key source hubs")
source_counts = collections.Counter((fk["source_schema"], fk["source_table"]) for fk in foreign_keys)
for (schema, table), count in source_counts.most_common(25):
    print(f"{schema}.{table} {count}")

print("\nForeign-key target hubs")
target_counts = collections.Counter((fk["target_schema"], fk["target_table"]) for fk in foreign_keys)
for (schema, table), count in target_counts.most_common(25):
    print(f"{schema}.{table} {count}")

print("\nConstraint types")
for kind, count in sorted(collections.Counter(c["type"] for c in constraints).items()):
    print(kind, count)

tables = {(r["schema"], r["name"]) for r in relations if r["kind"] == "table"}
pk_tables = {(c["schema"], c["table"]) for c in constraints if c["type"] == "primary key"}
no_pk = sorted(tables - pk_tables)
print(f"\nTables without primary key: {len(no_pk)} of {len(tables)}")
for schema, table in no_pk[:100]:
    print(f"{schema}.{table}")

print("\nIndex count by schema")
for schema, count in sorted(collections.Counter(i["schema"] for i in indexes).items()):
    print(schema, count)

